import React from 'react';
import { Link } from 'react-router-dom';

const B2BProductCard = ({ bike }) => {
    const formatPrice = (price) => {
        return new Intl.NumberFormat('en-IN').format(price);
    };

    return (
        <div className="b2b-card">
            {/* Image */}
            <div className="b2b-card-image">
                {bike.image_url ? (
                    <img src={bike.image_url} alt={bike.name} />
                ) : (
                    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%', fontSize: '3rem', opacity: 0.3 }}>🏍️</div>
                )}
                <div className="b2b-card-image-overlay"></div>
                <div className="b2b-card-badge">
                    <span className="b2b-brand-badge">{bike.brand || bike.category}</span>
                    {bike.verified && (
                        <span className="b2b-verified-badge">✓ Verified</span>
                    )}
                </div>
            </div>

            {/* Body */}
            <div className="b2b-card-body">
                <div className="b2b-card-title">{bike.name}</div>
                <div className="b2b-card-engine">{bike.engine_cc || '—'}cc • {bike.category}</div>

                <div className="b2b-card-specs">
                    <div className="b2b-spec">
                        <span className="b2b-spec-label">Bulk Price</span>
                        <span className="b2b-spec-value b2b-spec-value--accent">₹{formatPrice(bike.bulk_price || bike.price)}</span>
                    </div>
                    <div className="b2b-spec">
                        <span className="b2b-spec-label">MOQ</span>
                        <span className="b2b-spec-value">{bike.moq || 5} Units</span>
                    </div>
                    <div className="b2b-spec">
                        <span className="b2b-spec-label">In Stock</span>
                        <span className="b2b-spec-value b2b-spec-value--success">{bike.stock || '—'} Units</span>
                    </div>
                    <div className="b2b-spec">
                        <span className="b2b-spec-label">Rating</span>
                        <span className="b2b-spec-value">⭐ {bike.rating || '4.0'}</span>
                    </div>
                </div>

                <div className="b2b-delivery">
                    <span className="b2b-delivery-icon">🚚</span>
                    Delivery in {bike.delivery_days || 7}–{(bike.delivery_days || 7) + 3} days
                </div>

                <div className="b2b-card-divider"></div>

                <div className="b2b-card-footer">
                    <Link to={`/quote/${bike.id}`} className="btn btn-primary">
                        Request Quote
                    </Link>
                    <Link to={`/bike/${bike.id}`} className="btn btn-outline">
                        View Details
                    </Link>
                </div>
            </div>
        </div>
    );
};

export default B2BProductCard;
